namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _templates =
    [
        "New comment on your pull request",
        "Build succeeded for main branch",
        "Deployment to staging completed",
        "Code review requested by teammate",
        "Security alert: dependency update available",
        "Issue #42 was closed",
        "New release v2.1.0 published",
        "Pipeline failed — check logs",
    ];

    /// <summary>
    /// Returns a batch of fake notifications. Called once for the initial load
    /// and then repeatedly by the polling loop.
    /// </summary>
    public Task<List<NotificationItem>> GetLatestNotificationsAsync(int count = 3)
    {
        var rng = Random.Shared;
        var items = Enumerable.Range(0, count).Select(_ => new NotificationItem
        {
            Id = _nextId++,
            Message = _templates[rng.Next(_templates.Length)],
            Timestamp = DateTime.Now,
        }).ToList();

        return Task.FromResult(items);
    }
}

