@rendermode InteractiveServer
@implements IDisposable
@inject BlazorApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("T")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? PersistedNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Restore from prerender state if available; otherwise load once.
        if (PersistedNotifications is not null)
        {
            notifications = PersistedNotifications;
        }
        else
        {
            notifications = await NotificationService.GetLatestNotificationsAsync(5);
            PersistedNotifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is never called during prerender, so the polling
        // loop only starts once the page is truly interactive.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var fresh = await NotificationService.GetLatestNotificationsAsync(1);
                notifications.InsertRange(0, fresh);

                await InvokeAsync(StateHasChanged);
            }
            catch (TaskCanceledException)
            {
                // Expected on disposal — exit gracefully.
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

